.code-language) .markdown-rendered {
--code-block-padding: calc(var(--line-height-tight) * var(--code-size))
    calc(var(--line-height-normal) * var(--code-size));
}

.code-language) .markdown-rendered pre {
padding: var(--code-block-padding);
}

.code-language) .markdown-rendered pre[class*=language-] .copy-code-button {
padding-block: var(--size-2-1);
opacity: 1;
}

.code-language) .markdown-rendered pre[class*=language-] .copy-code-button:not([style="color: var(--text-success); display: inline-flex;"]) svg {
display: none;
}

.code-language) .markdown-rendered pre[class*=language-] .copy-code-button:not([style="color: var(--text-success); display: inline-flex;"])::before {
content: var(--code-lang, "Unkown");
font-family: var(--font-monospace);
color: var(--setting-code-language-color, var(--inline-code));
font-weight: 550;
}
